 16→
 17→
 18→public class HtmlQuoteCreator {
 19→    // Regular expressions to look for various HTML tags. This is no HTML::Parser, but hopefully it's good enough for
 20→    // our purposes.
 21→    private static final Pattern FIND_INSERTION_POINT_HTML = Pattern.compile("(?si:.*?(<html(?:>|\\s+[^>]*>)).*)");
 22→    private static final Pattern FIND_INSERTION_POINT_HEAD = Pattern.compile("(?si:.*?(<head(?:>|\\s+[^>]*>)).*)");
 23→    private static final Pattern FIND_INSERTION_POINT_BODY = Pattern.compile("(?si:.*?(<body(?:>|\\s+[^>]*>)).*)");
 24→    private static final Pattern FIND_INSERTION_POINT_HTML_END = Pattern.compile("(?si:.*(</html>).*?)");
 25→    private static final Pattern FIND_INSERTION_POINT_BODY_END = Pattern.compile("(?si:.*(</body>).*?)");
 26→    // The first group in a Matcher contains the first capture group. We capture the tag found in the above REs so that
 27→    // we can locate the *end* of that tag.
 28→    private static final int FIND_INSERTION_POINT_FIRST_GROUP = 1;
 29→    // HTML bits to insert as appropriate
 30→    // TODO is it safe to assume utf-8 here?
 31→    private static final String FIND_INSERTION_POINT_HTML_CONTENT = "<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\">\r\n<html>";
 32→    private static final String FIND_INSERTION_POINT_HTML_END_CONTENT = "</html>";
 33→    private static final String FIND_INSERTION_POINT_HEAD_CONTENT = "<head><meta content=\"text/html; charset=utf-8\" http-equiv=\"Content-Type\"></head>";
 34→    // Index of the start of the beginning of a String.
 35→    private static final int FIND_INSERTION_POINT_START_OF_STRING = 0;
 36→
 37→
 38→    /**
 39→     * Add quoting markup to a HTML message.
 40→     * @param originalMessage Metadata for message being quoted.
 41→     * @param messageBody Text of the message to be quoted.
 42→     * @param quoteStyle Style of quoting.
 43→     * @return Modified insertable message.
 44→     */
 45→    public static InsertableHtmlContent quoteOriginalHtmlMessage(Message originalMessage,
 46→            String messageBody, QuoteStyle quoteStyle) {
 47→        CoreResourceProvider resourceProvider = DI.get(CoreResourceProvider.class);
 48→        InsertableHtmlContent insertable = findInsertionPoints(messageBody);
 49→
 50→        String sentDate = new QuoteDateFormatter().format(originalMessage.getSentDate());
 51→        String fromAddress = Address.toString(originalMessage.getFrom());
 52→        if (quoteStyle == QuoteStyle.PREFIX) {
 53→            StringBuilder header = new StringBuilder();
 54→            header.append("<div class=\"gmail_quote\">");
 55→            if (sentDate.length() != 0) {
 56→                String replyHeader = resourceProvider.replyHeader(fromAddress, sentDate);
 57→                header.append(HtmlConverter.textToHtmlFragment(replyHeader));
 58→            } else {
 59→                String replyHeader = resourceProvider.replyHeader(fromAddress);
 60→                header.append(HtmlConverter.textToHtmlFragment(replyHeader));
 61→            }
 62→            header.append("<blockquote class=\"gmail_quote\" " +
 63→                    "style=\"margin: 0pt 0pt 0pt 0.8ex; border-left: 1px solid rgb(204, 204, 204); padding-left: 1ex;\">\r\n");
 64→
 65→            String footer = "</blockquote></div>";
 66→
 67→            insertable.insertIntoQuotedHeader(header.toString());
 68→            insertable.insertIntoQuotedFooter(footer);
 69→        } else if (quoteStyle == QuoteStyle.HEADER) {
 70→
 71→            StringBuilder header = new StringBuilder();
 72→            header.append("<div style='font-size:10.0pt;font-family:\"Tahoma\",\"sans-serif\";padding:3.0pt 0in 0in 0in'>\r\n");
 73→            header.append("<hr style='border:none;border-top:solid #E1E1E1 1.0pt'>\r\n"); // This gets converted into a horizontal line during html to text conversion.
 74→            if (originalMessage.getFrom() != null && fromAddress.length() != 0) {
 75→                header.append("<b>").append(resourceProvider.messageHeaderFrom()).append("</b> ")
 76→                        .append(HtmlConverter.textToHtmlFragment(fromAddress))
 77→                        .append("<br>\r\n");
 78→            }
 79→            if (sentDate.length() != 0) {
 80→                header.append("<b>").append(resourceProvider.messageHeaderDate()).append("</b> ")
 81→                        .append(sentDate)
 82→                        .append("<br>\r\n");
 83→            }
 84→            if (originalMessage.getRecipients(RecipientType.TO) != null && originalMessage.getRecipients(RecipientType.TO).length != 0) {
 85→                header.append("<b>").append(resourceProvider.messageHeaderTo()).append("</b> ")
 86→                        .append(HtmlConverter.textToHtmlFragment(Address.toString(originalMessage.getRecipients(RecipientType.TO))))
 87→                        .append("<br>\r\n");
 88→            }
 89→            if (originalMessage.getRecipients(RecipientType.CC) != null && originalMessage.getRecipients(RecipientType.CC).length != 0) {
 90→                header.append("<b>").append(resourceProvider.messageHeaderCc()).append("</b> ")
 91→                        .append(HtmlConverter.textToHtmlFragment(Address.toString(originalMessage.getRecipients(RecipientType.CC))))
 92→                        .append("<br>\r\n");
 93→            }
 94→            if (originalMessage.getSubject() != null) {
 95→                header.append("<b>").append(resourceProvider.messageHeaderSubject()).append("</b> ")
 96→                        .append(HtmlConverter.textToHtmlFragment(originalMessage.getSubject()))
 97→                        .append("<br>\r\n");
 98→            }
 99→            header.append("</div>\r\n");
100→            header.append("<br>\r\n");
101→
102→            insertable.insertIntoQuotedHeader(header.toString());
103→        }
104→
105→        return insertable;
106→    }
107→
108→    /**
109→     * <p>Find the start and end positions of the HTML in the string. This should be the very top
110→     * and bottom of the displayable message. It returns a {@link InsertableHtmlContent}, which
111→     * contains both the insertion points and potentially modified HTML. The modified HTML should be
112→     * used in place of the HTML in the original message.</p>
113→     *
114→     * <p>This method loosely mimics the HTML forward/reply behavior of BlackBerry OS 4.5/BIS 2.5,
115→     * which in turn mimics Outlook 2003 (as best I can tell).</p>
116→     *
117→     * @param content Content to examine for HTML insertion points
118→     * @return Insertion points and HTML to use for insertion.
119→     */
120→    private static InsertableHtmlContent findInsertionPoints(final String content) {
121→        InsertableHtmlContent insertable = new InsertableHtmlContent();
122→
123→        // If there is no content, don't bother doing any of the regex dancing.
124→        if (content == null || content.equals("")) {
125→            return insertable;
126→        }
127→
128→        // Search for opening tags.
129→        boolean hasHtmlTag = false;
130→        boolean hasHeadTag = false;
131→        boolean hasBodyTag = false;
132→        // First see if we have an opening HTML tag.  If we don't find one, we'll add one later.
133→        Matcher htmlMatcher = FIND_INSERTION_POINT_HTML.matcher(content);
134→        if (htmlMatcher.matches()) {
135→            hasHtmlTag = true;
136→        }
137→        // Look for a HEAD tag.  If we're missing a BODY tag, we'll use the close of the HEAD to start our content.
138→        Matcher headMatcher = FIND_INSERTION_POINT_HEAD.matcher(content);
139→        if (headMatcher.matches()) {
140→            hasHeadTag = true;
141→        }
142→        // Look for a BODY tag.  This is the ideal place for us to start our content.
143→        Matcher bodyMatcher = FIND_INSERTION_POINT_BODY.matcher(content);
144→        if (bodyMatcher.matches()) {
145→            hasBodyTag = true;
146→        }
147→
148→        Timber.d("Open: hasHtmlTag:%s hasHeadTag:%s hasBodyTag:%s", hasHtmlTag, hasHeadTag, hasBodyTag);
149→
150→        // Given our inspections, let's figure out where to start our content.
151→        // This is the ideal case -- there's a BODY tag and we insert ourselves just after it.
152→        if (hasBodyTag) {
153→            insertable.setQuotedContent(new StringBuilder(content));
154→            insertable.setHeaderInsertionPoint(bodyMatcher.end(FIND_INSERTION_POINT_FIRST_GROUP));
155→        } else if (hasHeadTag) {
156→            // Now search for a HEAD tag.  We can insert after there.
157→
158→            // If BlackBerry sees a HEAD tag, it inserts right after that, so long as there is no BODY tag. It doesn't
159→            // try to add BODY, either.  Right or wrong, it seems to work fine.
160→            insertable.setQuotedContent(new StringBuilder(content));
161→            insertable.setHeaderInsertionPoint(headMatcher.end(FIND_INSERTION_POINT_FIRST_GROUP));
162→        } else if (hasHtmlTag) {
163→            // Lastly, check for an HTML tag.
164→            // In this case, it will add a HEAD, but no BODY.
165→            StringBuilder newContent = new StringBuilder(content);
166→            // Insert the HEAD content just after the HTML tag.
167→            newContent.insert(htmlMatcher.end(FIND_INSERTION_POINT_FIRST_GROUP), FIND_INSERTION_POINT_HEAD_CONTENT);
168→            insertable.setQuotedContent(newContent);
169→            // The new insertion point is the end of the HTML tag, plus the length of the HEAD content.
170→            insertable.setHeaderInsertionPoint(htmlMatcher.end(FIND_INSERTION_POINT_FIRST_GROUP) + FIND_INSERTION_POINT_HEAD_CONTENT.length());
171→        } else {
172→            // If we have none of the above, we probably have a fragment of HTML.  Yahoo! and Gmail both do this.
173→            // Again, we add a HEAD, but not BODY.
174→            StringBuilder newContent = new StringBuilder(content);
175→            // Add the HTML and HEAD tags.
176→            newContent.insert(FIND_INSERTION_POINT_START_OF_STRING, FIND_INSERTION_POINT_HEAD_CONTENT);
177→            newContent.insert(FIND_INSERTION_POINT_START_OF_STRING, FIND_INSERTION_POINT_HTML_CONTENT);
178→            // Append the </HTML> tag.
179→            newContent.append(FIND_INSERTION_POINT_HTML_END_CONTENT);
180→            insertable.setQuotedContent(newContent);
181→            insertable.setHeaderInsertionPoint(FIND_INSERTION_POINT_HTML_CONTENT.length() + FIND_INSERTION_POINT_HEAD_CONTENT.length());
182→        }
183→
184→        // Search for closing tags. We have to do this after we deal with opening tags since it may
185→        // have modified the message.
186→        boolean hasHtmlEndTag = false;
187→        boolean hasBodyEndTag = false;
188→        // First see if we have an opening HTML tag.  If we don't find one, we'll add one later.
189→        Matcher htmlEndMatcher = FIND_INSERTION_POINT_HTML_END.matcher(insertable.getQuotedContent());
190→        if (htmlEndMatcher.matches()) {
191→            hasHtmlEndTag = true;
192→        }
193→        // Look for a BODY tag.  This is the ideal place for us to place our footer.
194→        Matcher bodyEndMatcher = FIND_INSERTION_POINT_BODY_END.matcher(insertable.getQuotedContent());
195→        if (bodyEndMatcher.matches()) {
196→            hasBodyEndTag = true;
197→        }
198→
199→        Timber.d("Close: hasHtmlEndTag:%s hasBodyEndTag:%s", hasHtmlEndTag, hasBodyEndTag);
200→
201→        // Now figure out where to put our footer.
202→        // This is the ideal case -- there's a BODY tag and we insert ourselves just before it.
203→        if (hasBodyEndTag) {
204→            insertable.setFooterInsertionPoint(bodyEndMatcher.start(FIND_INSERTION_POINT_FIRST_GROUP));
205→        } else if (hasHtmlEndTag) {
206→            // Check for an HTML tag.  Add ourselves just before it.
207→            insertable.setFooterInsertionPoint(htmlEndMatcher.start(FIND_INSERTION_POINT_FIRST_GROUP));
208→        } else {
209→            // If we have none of the above, we probably have a fragment of HTML.
210→            // Set our footer insertion point as the end of the string.
211→            insertable.setFooterInsertionPoint(insertable.getQuotedContent().length());
212→        }
213→
214→        return insertable;
215→    }
216→}
